const klines = $input.first().json;
const closes = [];
for (const k of Object.keys(klines)) {
  if (Array.isArray(klines[k])) {
    closes.push(parseFloat(klines[k][4]));
  }
}

if (closes.length === 0) {
  return [{ json: { error: 'No kline data' } }];
}

function calcRSI(prices, period = 14) {
  if (prices.length < period + 1) return 50;
  let gains = 0, losses = 0;
  const len = prices.length;
  for (let i = len - period; i < len; i++) {
    const diff = prices[i] - prices[i - 1];
    if (diff > 0) gains += diff;
    else losses -= diff;
  }
  const avgGain = gains / period;
  const avgLoss = losses / period;
  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return Math.round((100 - 100 / (1 + rs)) * 100) / 100;
}

const rsi = calcRSI(closes);
const lastPrice = closes[closes.length - 1];
let signal = 'HOLD';
if (rsi < 35) signal = 'BUY';
if (rsi > 65) signal = 'SELL';

return [{
  json: {
    pair: 'BTCUSDT',
    type: signal,
    entry: lastPrice,
    rsi: rsi,
    price: lastPrice,
    confidence: Math.round(Math.abs(rsi - 50) * 2),
    indicator: 'RSI(14)',
    timeframe: '1H',
    generated_at: new Date().toISOString()
  }
}];
